import React, { useState } from 'react';
import { Zap, Mail, Lock } from 'lucide-react';

export default function Login({ onLogin, onRegister }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);
    const result = await onLogin(email, password);
    if (!result.success) setError(result.message || 'Login failed');
    setLoading(false);
  };

  return (
    <div className="auth-page">
      <div className="auth-card">
        <div className="auth-logo"><Zap size={28} /></div>
        <h1>Welcome Back</h1>
        <p>Sign in to continue your fitness journey</p>
        
        <form onSubmit={handleSubmit}>
          {error && <div className="auth-error">{error}</div>}
          
          <div className="form-group">
            <label className="form-label">Email</label>
            <div style={{position: 'relative'}}>
              <Mail size={16} style={{position: 'absolute', left: '12px', top: '14px', color: '#666'}} />
              <input
                type="email"
                className="form-input"
                placeholder="Enter your email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                style={{paddingLeft: '38px'}}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Password</label>
            <div style={{position: 'relative'}}>
              <Lock size={16} style={{position: 'absolute', left: '12px', top: '14px', color: '#666'}} />
              <input
                type="password"
                className="form-input"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                style={{paddingLeft: '38px'}}
                required
              />
            </div>
          </div>

          <button type="submit" className="btn" disabled={loading}>
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>

        <p style={{textAlign: 'center', marginTop: '20px', color: '#aaa'}}>
          Don't have an account?{' '}
          <span style={{color: '#6366f1', cursor: 'pointer', fontWeight: '500'}} onClick={onRegister}>
            Sign Up
          </span>
        </p>
      </div>
    </div>
  );
}
